   422→async function loadBlpDataUrl(path: string): Promise<string> {
   423→  const cached = iconDataUrlCache.get(path);
   424→  if (cached) return cached;
   425→
   426→  const promise = (async () => {
   427→    const res = await fetch(path);
   428→    if (!res.ok) throw new Error(`Failed to fetch icon ${path}`);
   429→    const ab = await res.arrayBuffer();
   430→    const blp = decodeBLP(ab);
   431→    const img = getBLPImageData(blp, 0);
   432→    const pixelData = new Uint8ClampedArray(img.data);
   433→    if (shouldForceOpaqueOnZeroAlpha(path)) {
   434→      let allAlphaZero = true;
   435→      for (let i = 3; i < pixelData.length; i += 4) {
   436→        if (pixelData[i] !== 0) {
   437→          allAlphaZero = false;
   438→          break;
   439→        }
   440→      }
   441→      if (allAlphaZero) {
   442→        for (let i = 3; i < pixelData.length; i += 4) {
   443→          pixelData[i] = 255;
   444→        }
   445→      }
   446→    }
   447→    if (shouldApplyBlackColorKey(path)) {
   448→      for (let i = 0; i < pixelData.length; i += 4) {
   449→        const r = pixelData[i];
   450→        const g = pixelData[i + 1];
   451→        const b = pixelData[i + 2];
   452→        const a = pixelData[i + 3];
   453→        if (a > 224 && r <= 10 && g <= 10 && b <= 10) {
   454→          pixelData[i + 3] = 0;
   455→        }
   456→      }
   457→    }
   458→    const canvas = document.createElement("canvas");
   459→    canvas.width = img.width;
   460→    canvas.height = img.height;
   461→    const ctx = canvas.getContext("2d");
   462→    if (!ctx) throw new Error(`Failed to decode icon ${path}`);
   463→    ctx.putImageData(new ImageData(pixelData, img.width, img.height), 0, 0);
   464→    return canvas.toDataURL("image/png");
   465→  })();
   466→
   467→  iconDataUrlCache.set(path, promise);
   468→  return promise;
