export default function MenuButton({
  onClick,
  disabled,
  variant = "default",
  children,
}: Props) {
  const [urls, setUrls] = useState<NineSliceUrls>({
    bg: "",
    bgDown: "",
    bgDisabled: "",
    border: "",
    borderDown: "",
    borderDisabled: "",
    hover: "",
  });
  const [frameUrl, setFrameUrl] = useState("");

  useEffect(() => {
    const framePath =
      variant === "single" ? FRAME_SINGLE_PATH : FRAME_PATH;

