    ]).then(
      ([bg, bgDown, bgDisabled, border, borderDown, borderDisabled, hover, frame]) => {
        setUrls({ bg, bgDown, bgDisabled, border, borderDown, borderDisabled, hover });
        setFrameUrl(frame);
