file.content:
.build-orders-section {
  max-width: 1100px;
  margin: 0 auto;
  padding: 1.5rem;
}

/* ── Build order list ── */
.build-orders-list {
  display: flex;
  flex-direction: column;
  gap: 2rem;
}

/* ── Per-build card ── */
.build-card {
  display: grid;
  grid-template-columns: 1fr 2fr;
  gap: 0;
  background: rgba(0, 0, 0, 0.55);
  border: 1px solid rgba(252, 211, 18, 0.25);
}

/* ── Left column ── */
.build-card-info {
  padding: 1.25rem 1.25rem 1.25rem 1.5rem;
  border-right: 1px solid rgba(252, 211, 18, 0.2);
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.build-card-title {
  margin: 0;
  font-size: 1rem;
  font-weight: bold;
  color: var(--wc3-gold);
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
}

.build-card-matchup {
  margin: 0;
  font-size: 0.78rem;
  color: #c8b97a;
  font-style: italic;
}

.build-card-desc {
  margin: 0;
  font-size: 0.82rem;
  color: #dbe4ff;
  line-height: 1.5;
}

.build-card-note {
  margin: 0;
  font-size: 0.75rem;
  color: rgba(252, 211, 18, 0.7);
  font-style: italic;
}

.build-card-key-timing {
  font-size: 0.78rem;
  color: #c8b97a;
  padding: 0.35rem 0.6rem;
  border: 1px solid rgba(252, 211, 18, 0.2);
  background: rgba(252, 211, 18, 0.05);
}

.build-card-key-timing-label {
  color: var(--wc3-gold);
  font-weight: bold;
}

.build-card-timer {
  margin-top: auto;
  padding-top: 0.75rem;
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
}

.build-card-elapsed {
  font-size: 1.5rem;
  color: var(--wc3-gold);
  text-shadow: 0 0 8px rgba(252, 211, 18, 0.5);
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.05em;
}

.build-card-controls {
  display: flex;
  gap: 0.25rem;
  flex-wrap: wrap;
}

/* ── Right column: step table ── */
.build-card-steps {
  padding: 0.75rem 1rem;
  overflow-x: auto;
}

.build-steps-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.82rem;
}

.build-steps-table thead tr {
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
}

.build-steps-table th {
  padding: 0.4rem 0.6rem;
  text-align: left;
  color: var(--wc3-gold);
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: normal;
}

.build-steps-table td {
  padding: 0.45rem 0.6rem;
  color: #dbe4ff;
  vertical-align: middle;
}

/* ── Step states ── */
.build-step-row {
  transition: background 0.15s ease;
}

.build-step-row--past {
  opacity: 0.45;
}

.build-step-row--active td {
  color: var(--wc3-gold);
  text-shadow: 0 0 6px rgba(252, 211, 18, 0.35);
}

.build-step-order {
  width: 2rem;
  color: rgba(252, 211, 18, 0.6);
  font-size: 0.72rem;
}

.build-step-time {
  width: 4rem;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}

.build-step-instruction {
  /* flex column for most space */
}

.build-step-food {
  width: 4.5rem;
  white-space: nowrap;
  text-align: right;
}

