}

.wc3-listbox-item--selected {
  color: var(--wc3-gold);
  background: rgba(255, 255, 255, 0.12);
}

.wc3-listbox-scrollbar {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.wc3-listbox-scroll-arrow {
  width: 16px;
  height: 16px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
}

.wc3-listbox-scroll-arrow img {
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-scroll {
  position: relative;
  width: 18px;
  height: 96px;
}

.wc3-listbox-scroll-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-scroll-thumb {
  position: absolute;
  left: 50%;
  width: 16px;
  height: 16px;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-scroll input[type="range"] {
  position: absolute;
  inset: 0;
  margin: 0;
  opacity: 0;
  writing-mode: vertical-lr;
  cursor: pointer;
}

.wc3-bar {
  position: relative;
  width: 100%;
  margin: 0 auto;
  overflow: hidden;
}

.wc3-bar + .wc3-bar {
  margin-top: 8px;
}

.wc3-bar--large {
  height: 20px;
}

.wc3-bar--unit {
  width: min(
    100%,
    182.93px
  ); /* HPBarConsoleSmall/ManaBarConsoleSmall frame ratio: 0.04065 / 0.004 */
  height: 18px;
}

.wc3-bar--compact {
  width: min(
    100%,
    157.14px
  ); /* XpBarConsole/TimerBar frame ratio: 0.17776 / 0.01810 */
  height: 16px;
}

.wc3-bar--build {
  width: min(
    100%,
    163.7px
  ); /* BuildProgressBar frame ratio: 0.10538 / 0.01030 */
}

.wc3-bar-track,
.wc3-bar-border {
  position: absolute;
  inset: 0;
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-fill-wrap {
  position: absolute;
  inset: 0 auto 0 0;
  overflow: hidden;
  transition: width 620ms ease;
}

.wc3-bar-fill,
.wc3-bar-highlight {
  position: absolute;
  inset: 0;
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-fill--health {
  filter: saturate(1.18);
}

.wc3-bar-fill--mana {
  filter: saturate(1.2) hue-rotate(6deg);
}

.wc3-bar-fill--progress {
  filter: saturate(1.05);
}

.wc3-bar-fill--build {
  filter: saturate(1.12) hue-rotate(-9deg);
}

.wc3-bar-highlight {
  mix-blend-mode: screen;
  opacity: 0.62;
}

.wc3-bar-segments {
  position: absolute;
  inset: 2px;
  pointer-events: none;
  background-image: repeating-linear-gradient(
    to right,
    rgba(0, 0, 0, 0.38) 0 1px,
    rgba(0, 0, 0, 0) 1px 10%
  );
  opacity: 0.55;
}

.wc3-bar-text {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #f6f8ff;
  font-size: 0.74rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
}

.wc3-bar--compact .wc3-bar-text {
  font-size: 0.68rem;
}

.loading-preview {
  display: flex;
  justify-content: center;
}

.loading-bar-composite {
  position: relative;
  width: min(100%, 640px);
  aspect-ratio: 8.007 / 1; /* LoadBar.mdx border geoset ratio: 0.45804 / 0.05720 */
  height: auto;
  max-height: 80px;
  overflow: visible;
}

.loading-bar-composite .lb-track {
  position: absolute;
  overflow: hidden;
}

.loading-bar-composite .lb-bg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  background-repeat: repeat-x;
  background-size: auto 100%;
  image-rendering: auto;
}

.loading-bar-composite .lb-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 0%;
  background-repeat: repeat-x;
  background-size: auto 100%;
  image-rendering: auto;
  transition: width 90ms linear;
  will-change: width;
}

.loading-bar-composite .lb-border,
.loading-bar-composite .lb-glass {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  object-fit: fill;
  pointer-events: none;
}

.loading-bar-composite .lb-border {
  z-index: 1;
}

.loading-bar-composite .lb-glass {
  z-index: 2;
  opacity: 1;
}

.loading-bar-composite .lb-glow {
  position: absolute;
  height: auto;
  display: block;
  object-fit: fill;
  z-index: 4;
  mix-blend-mode: screen;
  mix-blend-mode: plus-lighter;
  pointer-events: none;
  transition:
    width 90ms linear,
    opacity 90ms linear;
}

.loading-bar-composite .lb-text {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 5;
  color: #f6f8ff;
  font-size: 0.78rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
}

.esc-slider-demo {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}

.esc-slider-value {
  color: #d8def5;
  font-size: 0.82rem;
}

.esc-slider-track {
  position: relative;
  width: 220px;
  height: 20px;
}

.esc-slider-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-slider-knob {
  position: absolute;
  top: 50%;
  width: 28px;
  height: 28px;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-slider-track input[type="range"] {
  position: absolute;
  inset: 0;
  opacity: 0;
  margin: 0;
  cursor: pointer;
}

.cmd-overlay-button {
  position: relative;
  width: 48px;
  height: 48px;
  border: 2px solid #1a1a2e;
  border-radius: 2px;
  overflow: hidden;
  background: #000;
}

.cmd-overlay-button--showcase {
  width: 64px;
  height: 64px;
}

.cmd-overlay-base,
.cmd-overlay-layer,
.cmd-overlay-level {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.cmd-overlay-add {
  mix-blend-mode: screen;
}

/* Hero Section */
.hero-section {
  text-align: center;
  padding: 24px 24px 32px;
  margin-bottom: 24px;
}

.hero-content {
  position: relative;
}

.hero-logo {
  display: block;
  margin: 0 auto 8px;
  width: min(420px, 60vw);
  height: auto;
  filter: drop-shadow(0 2px 6px rgba(0, 0, 0, 0.6));
  user-select: none;
  -webkit-user-drag: none;
}

.hero-subtitle {
  margin: 0 0 12px;
  color: #d3ddfb;
  font-size: 1.3rem;
}

.hero-description {
  margin: 0 0 24px;
  color: #9aa4c0;
  font-size: 0.95rem;
  line-height: 1.5;
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
}

.hero-description strong {
  color: #eceff7;
}

.hero-cta-row {
  display: flex;
  gap: 12px;
  justify-content: center;
  margin-bottom: 16px;
}

.hero-cta-row--components {
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
}

.hero-get-started-btn {
  width: 150px;
  height: 40px;
  flex: 0 0 150px;
  margin: 0;
}

.hero-install-editbox {
  width: 150px;
  height: 40px;
  flex: 0 0 150px;
  margin: 0;
  cursor: pointer;
}

.hero-install-editbox input {
  text-align: center;
  color: var(--wc3-gold);
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  font-size: 0.9rem;
  line-height: 1;
  cursor: pointer;
  padding: 0 8px;
}

.hero-version-label {
  margin: 6px 0 12px;
  color: #7c859d;
  font-size: 0.84rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.7);
}

.social-proof {
  margin: 0;
  color: #5a6080;
  font-size: 0.82rem;
  font-style: italic;
}

/* Faction Preview */
.faction-preview-section .section-desc {
  text-align: center;
  font-style: italic;
}

.faction-preview {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px;
}

.faction-preview-card {
  background: transparent;
  border: none;
  border-radius: 0;
  padding: 0;
  text-align: left;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.faction-preview-label {
  color: var(--wc3-dark-gold);
  font-size: 0.85rem;
  margin-bottom: 2px;
  text-align: center;
}

.faction-preview-samples {
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: center;
}

.faction-preview-control {
  width: min(100%, 192px);
  max-width: 192px;
}

.faction-preview-control-label {
  margin: 0 0 4px;
  color: #7982a0;
  font-size: 0.64rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.faction-preview-option-button {
  width: 192px;
  height: 36px;
}

.faction-preview-slider-demo {
  align-items: flex-start;
  gap: 3px;
}

.faction-preview-slider-track {
  width: 192px;
}

@media (max-width: 980px) {
  .faction-preview {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 640px) {
  .button-preview-col--textarea {
    width: 100%;
  }

  .faction-preview {
    grid-template-columns: 1fr;
  }
}

/* Install Section */
.install-section .code-block {
  margin-bottom: 12px;
}

.code-block {
  background: #0a0a14;
  border: 1px solid #222233;
  border-radius: 6px;
  padding: 14px 18px;
  overflow-x: auto;
}

.code-block code,
.code-block pre {
  margin: 0;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  font-size: 0.88rem;
  color: #c8d0e8;
  white-space: pre;
}

.install-note {
  margin: 16px 0 0;
  padding: 10px 16px;
  border-left: 3px solid var(--wc3-dark-gold);
  color: #9aa4c0;
  font-size: 0.88rem;
  line-height: 1.5;
}

.install-note code {
  color: var(--wc3-gold);
}

/* Design Tokens */
.token-grid {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-top: 14px;
}

.token-grid-header {
  display: grid;
  grid-template-columns: 164px repeat(4, 1fr);
  gap: 6px;
  margin-bottom: 4px;
}

.token-faction-label {
  text-align: center;
  color: #7b818d;
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.token-grid-row {
  display: grid;
  grid-template-columns: 164px repeat(4, 1fr);
  gap: 6px;
  align-items: center;
}

.token-name {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.token-name code {
  color: var(--wc3-gold);
  font-size: 0.72rem;
}

.token-label {
  color: #5a6080;
  font-size: 0.66rem;
}

.token-swatch {
  position: relative;
  width: 100%;
  min-height: 44px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  overflow: hidden;
}

.token-swatch--editbox-canvas {
  background: transparent;
}

.token-swatch-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.token-hex {
  position: relative;
  z-index: 1;
  width: 100%;
  display: block;
  text-align: center;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  font-size: 0.86rem;
  line-height: 1.1;
  letter-spacing: 0.02em;
  color: var(--token-hex-color);
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.72);
}

.token-caption {
  margin: 16px 0 0;
  color: #5a6080;
  font-size: 0.85rem;
  text-align: center;
}

/* Accessibility */
.a11y-checklist {
  display: flex;
  flex-wrap: wrap;
  gap: 8px 16px;
  margin-top: 14px;
}

.a11y-check-item {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  color: #c8d0e8;
  font-size: 0.88rem;
}

.a11y-check-icon {
  color: #58d869;
  font-size: 1rem;
}

/* Bundle Size Chart */
.bundle-chart {
  --bundle-bar-width: 164px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin: 14px auto 0;
  width: fit-content;
  max-width: 100%;
}

.bundle-chart-row {
  display: grid;
  grid-template-columns: 130px var(--bundle-bar-width) 50px;
  gap: 10px;
  align-items: center;
}

.bundle-chart-label {
  color: #c8d0e8;
  font-size: 0.82rem;
  text-align: right;
}

.bundle-chart-bar-track {
  position: relative;
  height: 16px;
  width: var(--bundle-bar-width);
  background: #0a0a14;
  border-radius: 2px;
  overflow: hidden;
}

.bundle-chart-bar-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: auto;
  pointer-events: none;
}

.bundle-chart-size {
  color: #7b818d;
  font-size: 0.78rem;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

/* FAQ */
.faq-section h3 {
  margin-bottom: 14px;
}

.faq-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.faq-item {
  border-top: 1px solid rgba(88, 104, 158, 0.45);
  padding-top: 10px;
}

.faq-item:first-child {
  border-top: none;
  padding-top: 0;
}

.faq-question-heading {
  margin: 0 0 4px;
  color: #e2e9ff;
  font-size: 0.92rem;
  font-weight: 400;
}

.faq-answer-text {
  margin: 0;
  color: #9aa4c0;
  font-size: 0.88rem;
  line-height: 1.5;
}

/* Footer */
.site-footer {
  position: relative;
  isolation: isolate;
  overflow: visible;
  text-align: center;
  padding: 44px clamp(96px, 12vw, 150px) 36px;
  margin-top: 8px;
  border-top: 1px solid #1e1e30;
}

.footer-content {
  position: relative;
  z-index: 5;
}

.footer-worker-unit {
  position: absolute;
  bottom: calc(-44px - var(--footer-worker-y-offset, 0px));
  width: clamp(138px, 12.1vw, 186px);
  height: clamp(250px, 21vw, 332px);
  pointer-events: none;
  z-index: 20;
}

.footer-worker-unit--left {
  left: clamp(0px, 0.9vw, 18px);
}

.footer-worker-unit--right {
  right: clamp(0px, 0.9vw, 18px);
  transform: scaleX(-1);
}

.footer-links {
  margin: 0 0 8px;
  color: #7b818d;
  font-size: 0.85rem;
}

.footer-links a {
  color: var(--wc3-dark-gold);
  text-decoration: none;
}

.footer-links a:hover {
  color: var(--wc3-gold);
  text-decoration: underline;
}

.footer-joke {
  margin: 0;
  color: #3a3f54;
  font-size: 0.78rem;
}

.footer-signoff {
  margin: 2rem 0 0;
  color: #7b818d;
  font-size: 0.85rem;
}

.resource-counter {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 1rem;
  color: #eceff7;
  text-shadow:
    0 1px 2px #000,
    0 0 2px #000;
  white-space: nowrap;
}

.resource-counter img {
  width: 20px;
  height: 20px;
  image-rendering: pixelated;
}

/* Command Card (Hotkey) Buttons */
@property --sweep {
  syntax: "<angle>";
  inherits: false;
  initial-value: 360deg;
}

.cmd-btn {
  position: relative;
  width: 48px;
  height: 48px;
  border: none;
  border-radius: 0;
  overflow: hidden;
  cursor: pointer;
  padding: 0;
  background: transparent;
  flex-shrink: 0;
  color: #f0d775;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

.cmd-btn--showcase {
  width: 64px;
  height: 64px;
}

.cmd-btn:focus-visible {
  outline: 1px solid #f0d775;
  outline-offset: 1px;
}

.cmd-btn:disabled {
  cursor: default;
}

.cmd-btn img {
  image-rendering: pixelated;
}

.cmd-btn-backdrop,
.cmd-btn-icon,
.cmd-btn-frame {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  pointer-events: none;
}

.cmd-btn-backdrop {
  z-index: 1;
}

.cmd-btn-icon {
  z-index: 2;
}

.cmd-btn-frame {
  z-index: 3;
}

.cmd-btn-highlight {
  position: absolute;
  inset: 0;
  background-size: 100% 100%;
  mix-blend-mode: screen;
  opacity: 0;
  transition: opacity 80ms linear;
  pointer-events: none;
  z-index: 4;
}

.cmd-btn:hover .cmd-btn-highlight,
.cmd-btn-highlight.cmd-btn-highlight--on {
  opacity: 1;
}

.cmd-btn--pressed img {
  filter: brightness(0.7);
}

.cmd-btn--pressed {
  transform: translate(1px, 1px);
}

.cmd-btn-hotkey {
  position: absolute;
  right: 2px;
  bottom: 2px;
  font-size: 0.62rem;
  font-weight: 700;
  line-height: 1;
  color: #f0d775;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
  user-select: none;
  z-index: 5;
}

@keyframes cooldown-sweep {
  from {
    --sweep: 360deg;
  }
  to {
    --sweep: 0deg;
  }
}

.cmd-btn-cooldown {
  position: absolute;
  inset: 0;
  background: conic-gradient(
    from 0deg,
    rgba(0, 0, 0, 0.75) var(--sweep),
    transparent var(--sweep)
  );
  animation: cooldown-sweep 8s linear infinite;
  pointer-events: none;
  z-index: 6;
}

.cmd-btn-no-resources {
  position: absolute;
  inset: 0;
  background: rgba(255, 40, 40, 0.35);
  pointer-events: none;
  z-index: 6;
}

.cmd-btn--no-resources .cmd-btn-hotkey {
  color: #ffb3b3;
}

.command-card-preview {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.command-card-grid {
  display: grid;
  grid-template-columns: repeat(4, 64px);
  grid-template-rows: repeat(3, 64px);
  gap: 8px;
  padding: 0;
}

.command-card-cell {
  width: 64px;
  height: 64px;
}

.command-card-cell .cmd-btn {
  width: 100%;
  height: 100%;
}

.command-card-cell .cmd-btn-hotkey {
  right: 3px;
  bottom: 3px;
  font-size: 0.78rem;
}

.cmd-btn-fallback-icon {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #dbe5ff;
  background: radial-gradient(
    circle at 35% 30%,
    #2f4f96 0%,
    #112342 60%,
    #090f1e 100%
  );
  font-size: 1.05rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
  pointer-events: none;
  z-index: 2;
}

.cmd-btn-empty {
  cursor: default;
  background-color: #020308;
}

.cmd-btn--passive .cmd-btn-icon {
  filter: saturate(0.72) brightness(0.88);
}

.cmd-btn--levelup .cmd-btn-icon {
  filter: saturate(1.1) brightness(1.08);
}

.cmd-btn--levelup .cmd-btn-hotkey {
  color: #ffd843;
}

.unit-queue-preview {
  display: flex;
  justify-content: center;
}

.unit-queue-stage {
  position: relative;
  width: min(100%, 482px);
  aspect-ratio: 241 / 93;
}

.unit-queue-canvas,
.unit-queue-fallback {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
}

.unit-queue-canvas {
  image-rendering: auto;
}

.unit-queue-fallback {
  border: 1px solid #1f2636;
  border-radius: 6px;
  background-color: #070912;
}

.tooltip-preview-grid {
  display: grid;
  gap: 10px;
  justify-items: start;
}

/* WC3 data refs: MiscUI ToolTip* font heights = 0.011, InfoPanel gold text ~ #fcd312. */
.tooltip-preview {
  position: relative;
  width: min(100%, 384px);
  border: 10px solid transparent;
  border-color: rgba(244, 212, 94, 0.35);
  border-image: var(--tooltip-border) 33.333% fill / 10px;
  background-color: #0a0d16;
  background-image: var(--tooltip-bg);
  background-repeat: repeat;
  background-size: auto;
  padding: 10px 12px;
  color: #f4f7ff;
}

.tooltip-preview--simple {
  width: min(100%, 340px);
}

.tooltip-preview--error {
  color: #eec9c9;
}

.tooltip-preview-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.tooltip-preview-head h4 {
  margin: 0;
  color: var(--wc3-gold);
  font-size: 0.72rem;
  line-height: 1.2;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.85);
}

.tooltip-preview p {
  margin: 6px 0 0;
  color: #f1f5ff;
  font-size: 0.72rem;
  line-height: 1.35;
}

.tooltip-hotkey {
  padding: 0;
  color: #fed312;
  font-family: inherit;
  font-size: 0.72rem;
  letter-spacing: 0.01em;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.85);
}

.tooltip-costs {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 8px;
}

.tooltip-cost {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  color: #ffffff;
  font-size: 0.72rem;
}

.tooltip-cost img {
  width: 14px;
  height: 14px;
  image-rendering: pixelated;
}

.portrait-showcase {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.portrait-stage-wrap {
  position: relative;
  width: min(225px, 52vw);
}

.portrait-stage {
  position: relative;
  width: 100%;
  aspect-ratio: 130 / 160;
  image-rendering: pixelated;
  z-index: 2;
}

.portrait-window {
  position: absolute;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  -webkit-mask-image: var(--portrait-window-mask);
  mask-image: var(--portrait-window-mask);
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-size: 100% 100%;
  mask-size: 100% 100%;
  -webkit-mask-position: center;
  mask-position: center;
  overflow: hidden;
  background: #000;
  z-index: 1;
}

.portrait-frame-overlay {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: fill;
  pointer-events: none;
  z-index: 2;
}

.minimap-showcase {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
}

.minimap-frame {
  position: relative;
  width: 220px;
  height: 220px;
  overflow: hidden;
  border: 2px solid #2a3555;
  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.06);
  background: #090d17;
}

.minimap-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  opacity: 0.78;
}

.minimap-fog {
  position: absolute;
  inset: 0;
  background: radial-gradient(
    circle at 50% 50%,
    rgba(0, 0, 0, 0) 32%,
    rgba(0, 0, 0, 0.68) 100%
  );
  pointer-events: none;
}

.minimap-ping {
  position: absolute;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.75);
  box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.45);
  animation: minimap-ping 1.8s ease-out infinite;
}

.minimap-ping--a {
  left: 26%;
  top: 34%;
  background: #58d869;
}

.minimap-ping--b {
  left: 61%;
  top: 54%;
  background: #e65a5a;
  animation-delay: 0.6s;
}

.minimap-ping--c {
  left: 47%;
  top: 20%;
  background: #f0d775;
  animation-delay: 1.1s;
}

@keyframes minimap-ping {
  0% {
    box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.45);
  }
  100% {
    box-shadow: 0 0 0 12px rgba(255, 255, 255, 0);
  }
}

.minimap-legend {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  justify-content: center;
  color: #9ca8c5;
  font-size: 0.76rem;
}

.minimap-legend span {
