}

.hero-card-body {
  flex: 1;
  min-width: 0;
}

.hero-card-head h4 {
  margin: 0;
  color: var(--wc3-gold);
  font-size: 1rem;
}

.hero-card-head span {
  color: #9cabcf;
  font-size: 0.78rem;
}

.hero-card-bars {
  margin-top: 8px;
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.hero-card-bar {
  position: relative;
  height: 12px;
  border: 1px solid #2f3f68;
  border-radius: 3px;
  background: #070b14;
