  text-align: center;
  padding: 24px 0;
}

@media (max-width: 640px) {
  .borders-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 10px 8px;
  }

  .border-thumbnail {
    max-width: 132px;
    height: 84px;
  }

  .border-label {
    font-size: 0.74rem;
  }
