.timer-section {
  text-align: center;
  padding: 2rem;
}
.timer-display {
  font-family: "Friz Quadrata", serif;
  font-size: 4rem;
  color: #fcd312;
  margin: 1rem 0;
  letter-spacing: 0.05em;
}
.timer-controls {
  display: flex;
  gap: 1rem;
  justify-content: center;
  margin-top: 1rem;
}

.build-orders-section {
  max-width: 1100px;
  margin: 0 auto;
  padding: 1.5rem;
}

/* ── Build order list ── */
.build-orders-list {
  display: flex;
  flex-direction: column;
  gap: 2rem;
}

/* ── Per-build card ── */
.build-card {
  display: grid;
  grid-template-columns: 1fr 2fr;
  gap: 0;
  background: rgba(0, 0, 0, 0.55);
  border: 1px solid rgba(252, 211, 18, 0.25);
}

/* ── Left column ── */
.build-card-info {
  padding: 1.25rem 1.25rem 1.25rem 1.5rem;
  border-right: 1px solid rgba(252, 211, 18, 0.2);
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.build-card-title {
  margin: 0;
  font-size: 1rem;
