  color: var(--wc3-gold);
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
}

.build-card-matchup {
  margin: 0;
  font-size: 0.78rem;
  color: #c8b97a;
  font-style: italic;
}

.build-card-desc {
  margin: 0;
  font-size: 0.82rem;
  color: #dbe4ff;
  line-height: 1.5;
}

.build-card-note {
  margin: 0;
  font-size: 0.75rem;
  color: rgba(252, 211, 18, 0.7);
  font-style: italic;
}

.build-card-key-timing {
  font-size: 0.78rem;
  color: #c8b97a;
  padding: 0.35rem 0.6rem;
  border: 1px solid rgba(252, 211, 18, 0.2);
