.build-card-key-timing-label {
  color: var(--wc3-gold);
  font-weight: bold;
}

.build-card-timer {
  margin-top: auto;
  padding-top: 0.75rem;
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
}

.build-card-elapsed {
  font-size: 1.5rem;
  color: var(--wc3-gold);
