}

.build-step-order {
  width: 2rem;
  color: rgba(252, 211, 18, 0.6);
  font-size: 0.72rem;
}

.build-step-time {
  width: 4rem;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}

.build-step-instruction {
  /* flex column for most space */
}

.build-step-food {
  width: 4.5rem;
  white-space: nowrap;
  text-align: right;
}

