.popup-trigger-button {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 220px;
  height: 36px;
  border: none;
  background: transparent;
  color: var(--wc3-gold);
  font-family: inherit;
  font-size: 0.84rem;
  line-height: 1;
  padding: 0 12px;
  cursor: pointer;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.popup-trigger-button:disabled {
  cursor: default;
}

.popup-trigger-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.popup-title-text,
.popup-arrow-icon {
  position: relative;
  z-index: 2;
}

.popup-title-text {
  flex: 1;
  text-align: left;
  color: var(--wc3-gold);
}

.popup-title-text-disabled {
  color: #808080;
}

.popup-arrow-icon {
  width: 16px;
  height: 16px;
  image-rendering: pixelated;
}

.popup-trigger-anchor {
  position: relative;
  width: 220px;
}

.popup-menu-demo {
