.bundle-chart-label {
  color: #c8d0e8;
  font-size: 0.82rem;
  text-align: right;
}

.bundle-chart-bar-track {
  position: relative;
  height: 16px;
  width: var(--bundle-bar-width);
  background: #0a0a14;
  border-radius: 2px;
  overflow: hidden;
}

.bundle-chart-bar-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: auto;
  pointer-events: none;
}

.bundle-chart-size {
  color: #7b818d;
  font-size: 0.78rem;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

/* FAQ */
.faq-section h3 {
  margin-bottom: 14px;
}

.faq-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.faq-item {
  border-top: 1px solid rgba(88, 104, 158, 0.45);
  padding-top: 10px;
}

.faq-item:first-child {
  border-top: none;
  padding-top: 0;
}

.faq-question-heading {
  margin: 0 0 4px;
  color: #e2e9ff;
  font-size: 0.92rem;
  font-weight: 400;
}

.faq-answer-text {
  margin: 0;
  color: #9aa4c0;
  font-size: 0.88rem;
  line-height: 1.5;
}

/* Footer */
.site-footer {
  position: relative;
  isolation: isolate;
  overflow: visible;
  text-align: center;
  padding: 44px clamp(96px, 12vw, 150px) 36px;
  margin-top: 8px;
  border-top: 1px solid #1e1e30;
}

.footer-content {
  position: relative;
  z-index: 5;
}

.footer-worker-unit {
  position: absolute;
  bottom: calc(-44px - var(--footer-worker-y-offset, 0px));
  width: clamp(138px, 12.1vw, 186px);
  height: clamp(250px, 21vw, 332px);
  pointer-events: none;
  z-index: 20;
}

.footer-worker-unit--left {
  left: clamp(0px, 0.9vw, 18px);
}

.footer-worker-unit--right {
  right: clamp(0px, 0.9vw, 18px);
  transform: scaleX(-1);
}

.footer-links {
  margin: 0 0 8px;
  color: #7b818d;
  font-size: 0.85rem;
}

.footer-links a {
  color: var(--wc3-dark-gold);
  text-decoration: none;
}

.footer-links a:hover {
  color: var(--wc3-gold);
  text-decoration: underline;
}

.footer-joke {
  margin: 0;
  color: #3a3f54;
  font-size: 0.78rem;
}

.footer-signoff {
  margin: 2rem 0 0;
  color: #7b818d;
  font-size: 0.85rem;
}

.resource-counter {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 1rem;
  color: #eceff7;
  text-shadow:
    0 1px 2px #000,
    0 0 2px #000;
  white-space: nowrap;
}

.resource-counter img {
  width: 20px;
  height: 20px;
  image-rendering: pixelated;
}

/* Command Card (Hotkey) Buttons */
@property --sweep {
  syntax: "<angle>";
  inherits: false;
  initial-value: 360deg;
}

.cmd-btn {
  position: relative;
  width: 48px;
  height: 48px;
  border: none;
  border-radius: 0;
  overflow: hidden;
  cursor: pointer;
  padding: 0;
  background: transparent;
  flex-shrink: 0;
  color: #f0d775;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

.cmd-btn--showcase {
  width: 64px;
  height: 64px;
}

.cmd-btn:focus-visible {
  outline: 1px solid #f0d775;
  outline-offset: 1px;
}

.cmd-btn:disabled {
  cursor: default;
}

.cmd-btn img {
  image-rendering: pixelated;
}

.cmd-btn-backdrop,
.cmd-btn-icon,
.cmd-btn-frame {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  pointer-events: none;
}

.cmd-btn-backdrop {
  z-index: 1;
}

.cmd-btn-icon {
  z-index: 2;
}

.cmd-btn-frame {
  z-index: 3;
}

.cmd-btn-highlight {
  position: absolute;
  inset: 0;
  background-size: 100% 100%;
  mix-blend-mode: screen;
  opacity: 0;
  transition: opacity 80ms linear;
  pointer-events: none;
  z-index: 4;
}

.cmd-btn:hover .cmd-btn-highlight,
.cmd-btn-highlight.cmd-btn-highlight--on {
  opacity: 1;
}

.cmd-btn--pressed img {
  filter: brightness(0.7);
}

.cmd-btn--pressed {
  transform: translate(1px, 1px);
}

.cmd-btn-hotkey {
  position: absolute;
  right: 2px;
  bottom: 2px;
  font-size: 0.62rem;
  font-weight: 700;
  line-height: 1;
  color: #f0d775;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
  user-select: none;
  z-index: 5;
}

@keyframes cooldown-sweep {
  from {
    --sweep: 360deg;
  }
  to {
    --sweep: 0deg;
  }
}

.cmd-btn-cooldown {
  position: absolute;
  inset: 0;
  background: conic-gradient(
    from 0deg,
    rgba(0, 0, 0, 0.75) var(--sweep),
    transparent var(--sweep)
  );
  animation: cooldown-sweep 8s linear infinite;
  pointer-events: none;
  z-index: 6;
}

.cmd-btn-no-resources {
  position: absolute;
  inset: 0;
  background: rgba(255, 40, 40, 0.35);
  pointer-events: none;
  z-index: 6;
}

.cmd-btn--no-resources .cmd-btn-hotkey {
  color: #ffb3b3;
}

.command-card-preview {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.command-card-grid {
  display: grid;
  grid-template-columns: repeat(4, 64px);
  grid-template-rows: repeat(3, 64px);
  gap: 8px;
  padding: 0;
}

.command-card-cell {
  width: 64px;
  height: 64px;
}

.command-card-cell .cmd-btn {
  width: 100%;
  height: 100%;
}

.command-card-cell .cmd-btn-hotkey {
  right: 3px;
  bottom: 3px;
  font-size: 0.78rem;
}

.cmd-btn-fallback-icon {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #dbe5ff;
  background: radial-gradient(
    circle at 35% 30%,
    #2f4f96 0%,
    #112342 60%,
    #090f1e 100%
  );
  font-size: 1.05rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
  pointer-events: none;
  z-index: 2;
}

.cmd-btn-empty {
  cursor: default;
  background-color: #020308;
}

.cmd-btn--passive .cmd-btn-icon {
  filter: saturate(0.72) brightness(0.88);
}

.cmd-btn--levelup .cmd-btn-icon {
  filter: saturate(1.1) brightness(1.08);
}

.cmd-btn--levelup .cmd-btn-hotkey {
  color: #ffd843;
}

.unit-queue-preview {
  display: flex;
  justify-content: center;
}

.unit-queue-stage {
  position: relative;
  width: min(100%, 482px);
  aspect-ratio: 241 / 93;
}

.unit-queue-canvas,
.unit-queue-fallback {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
}

.unit-queue-canvas {
  image-rendering: auto;
}

.unit-queue-fallback {
  border: 1px solid #1f2636;
  border-radius: 6px;
  background-color: #070912;
}

.tooltip-preview-grid {
  display: grid;
  gap: 10px;
  justify-items: start;
}

/* WC3 data refs: MiscUI ToolTip* font heights = 0.011, InfoPanel gold text ~ #fcd312. */
.tooltip-preview {
  position: relative;
  width: min(100%, 384px);
  border: 10px solid transparent;
  border-color: rgba(244, 212, 94, 0.35);
  border-image: var(--tooltip-border) 33.333% fill / 10px;
  background-color: #0a0d16;
  background-image: var(--tooltip-bg);
  background-repeat: repeat;
  background-size: auto;
  padding: 10px 12px;
  color: #f4f7ff;
}

.tooltip-preview--simple {
  width: min(100%, 340px);
}

.tooltip-preview--error {
  color: #eec9c9;
}

.tooltip-preview-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.tooltip-preview-head h4 {
  margin: 0;
  color: var(--wc3-gold);
  font-size: 0.72rem;
  line-height: 1.2;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.85);
}

.tooltip-preview p {
  margin: 6px 0 0;
  color: #f1f5ff;
  font-size: 0.72rem;
  line-height: 1.35;
}

.tooltip-hotkey {
  padding: 0;
  color: #fed312;
  font-family: inherit;
  font-size: 0.72rem;
  letter-spacing: 0.01em;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.85);
}

.tooltip-costs {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 8px;
}

.tooltip-cost {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  color: #ffffff;
  font-size: 0.72rem;
}

.tooltip-cost img {
  width: 14px;
  height: 14px;
  image-rendering: pixelated;
}

.portrait-showcase {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.portrait-stage-wrap {
  position: relative;
  width: min(225px, 52vw);
}

.portrait-stage {
  position: relative;
  width: 100%;
  aspect-ratio: 130 / 160;
  image-rendering: pixelated;
  z-index: 2;
}

.portrait-window {
  position: absolute;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  -webkit-mask-image: var(--portrait-window-mask);
  mask-image: var(--portrait-window-mask);
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-size: 100% 100%;
  mask-size: 100% 100%;
  -webkit-mask-position: center;
  mask-position: center;
  overflow: hidden;
  background: #000;
  z-index: 1;
}

.portrait-frame-overlay {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: fill;
  pointer-events: none;
  z-index: 2;
}

.minimap-showcase {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
}

.minimap-frame {
  position: relative;
  width: 220px;
  height: 220px;
  overflow: hidden;
  border: 2px solid #2a3555;
  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.06);
  background: #090d17;
}

.minimap-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  opacity: 0.78;
}

.minimap-fog {
  position: absolute;
  inset: 0;
  background: radial-gradient(
    circle at 50% 50%,
    rgba(0, 0, 0, 0) 32%,
    rgba(0, 0, 0, 0.68) 100%
  );
  pointer-events: none;
}

.minimap-ping {
  position: absolute;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.75);
  box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.45);
  animation: minimap-ping 1.8s ease-out infinite;
}

.minimap-ping--a {
  left: 26%;
  top: 34%;
  background: #58d869;
}

.minimap-ping--b {
  left: 61%;
  top: 54%;
  background: #e65a5a;
  animation-delay: 0.6s;
}

.minimap-ping--c {
  left: 47%;
  top: 20%;
  background: #f0d775;
  animation-delay: 1.1s;
}

@keyframes minimap-ping {
  0% {
    box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.45);
  }
  100% {
    box-shadow: 0 0 0 12px rgba(255, 255, 255, 0);
  }
}

.minimap-legend {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  justify-content: center;
  color: #9ca8c5;
  font-size: 0.76rem;
}

.minimap-legend span {
  display: inline-flex;
  align-items: center;
  gap: 5px;
}

.dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  display: inline-block;
}

.dot--ally {
  background: #58d869;
}
.dot--enemy {
  background: #e65a5a;
}
.dot--neutral {
  background: #f0d775;
}

.dialog-preview-wrap {
  position: relative;
  min-height: 70px;
}

.dialog-trigger {
  border: 1px solid #44557f;
  border-radius: 4px;
  background: #0f1527;
  color: #dce5fb;
  padding: 8px 12px;
  font-family: inherit;
  cursor: pointer;
}

.dialog-trigger:hover {
  border-color: #6b7fae;
}

.dialog-scrim {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(3, 5, 11, 0.65);
  z-index: 50;
}

.dialog-preview {
  width: min(420px, calc(100vw - 32px));
  border: 1px solid #2f3d63;
  border-radius: 6px;
  background: linear-gradient(180deg, #12192d 0%, #0b1020 100%);
  box-shadow: 0 18px 40px rgba(0, 0, 0, 0.55);
  padding: 14px 16px;
}

.dialog-preview h4 {
  margin: 0;
  color: var(--wc3-gold);
  font-size: 1rem;
}

.dialog-preview p {
  margin: 8px 0 0;
  color: #c8d0e8;
  font-size: 0.86rem;
  line-height: 1.45;
}

.dialog-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  margin-top: 12px;
}

.dialog-btn {
  border: 1px solid #4a5c86;
  border-radius: 4px;
  background: #121a30;
  color: #dce5fb;
  padding: 6px 11px;
  font-family: inherit;
  cursor: pointer;
}

.dialog-btn:hover {
  border-color: #6780bb;
}

.dialog-btn--secondary {
  border-color: #505a79;
  color: #d4d9e8;
}

.dialog-btn--danger {
  border-color: #8f4a4a;
  background: #2a1418;
  color: #f4d2d2;
}

.chat-preview {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.chat-log {
  border: 1px solid #1f2a46;
  border-radius: 6px;
  background: #090d18;
  padding: 10px;
  max-height: 170px;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.chat-line {
  font-size: 0.82rem;
  line-height: 1.35;
}

.chat-from {
  font-weight: 700;
  margin-right: 6px;
}

.chat-line--ally {
  color: #8fc0ff;
}
.chat-line--enemy {
  color: #f29090;
}
.chat-line--system {
  color: #f0d775;
  font-style: italic;
}
.chat-line--whisper {
  color: #c4a4ff;
}

.chat-input-row {
  display: flex;
  gap: 8px;
}

.chat-input-row input {
  flex: 1;
  border: 1px solid #2a3453;
  border-radius: 4px;
  background: #0a0f1c;
  color: #dce5fb;
  font-family: inherit;
  padding: 7px 9px;
}

.chat-input-row button {
  border: 1px solid #43527b;
  border-radius: 4px;
  background: #111a30;
  color: #dce5fb;
  font-family: inherit;
  padding: 7px 12px;
}

.hero-card-stack {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.hero-card-preview {
  display: flex;
  gap: 12px;
  align-items: flex-start;
  border: 1px solid #2a3554;
  border-radius: 6px;
  background: linear-gradient(180deg, #0d1323 0%, #080d1a 100%);
  padding: 12px;
}

.hero-card-portrait-wrap {
  position: relative;
}

.hero-card-portrait {
  width: 78px;
  height: 78px;
}

.hero-card-level {
  position: absolute;
  right: -6px;
  bottom: -4px;
  min-width: 20px;
  padding: 1px 5px;
  border: 1px solid rgba(255, 212, 18, 0.58);
  border-radius: 10px;
  background: rgba(0, 0, 0, 0.8);
  color: var(--wc3-gold);
  font-size: 0.72rem;
  text-align: center;
}

.hero-card-body {
  flex: 1;
  min-width: 0;
}

.hero-card-head h4 {
  margin: 0;
  color: var(--wc3-gold);
  font-size: 1rem;
}

.hero-card-head span {
  color: #9cabcf;
  font-size: 0.78rem;
}

.hero-card-bars {
  margin-top: 8px;
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.hero-card-bar {
  position: relative;
  height: 12px;
  border: 1px solid #2f3f68;
  border-radius: 3px;
  background: #070b14;
  overflow: hidden;
}

.hero-card-bar-fill {
  position: absolute;
  inset: 0 auto 0 0;
  height: 100%;
}

.hero-card-bar-fill--hp {
  background: linear-gradient(90deg, #3abf3a 0%, #58d869 100%);
}

.hero-card-bar-fill--mp {
  background: linear-gradient(90deg, #3a58d2 0%, #6280ff 100%);
}

.hero-card-bar span {
  position: relative;
  display: block;
  text-align: center;
  color: #ecf1ff;
  font-size: 0.66rem;
  line-height: 10px;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.hero-card-stats {
  margin-top: 8px;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 4px 10px;
  color: #b4c0dd;
  font-size: 0.73rem;
}

.hero-card-stats b {
  color: #e0e8ff;
  font-weight: 700;
}

.hero-card-abilities {
  margin-top: 9px;
  display: flex;
  gap: 6px;
}

.hero-card-ability {
  width: 30px;
  height: 30px;
  border: 1px solid #2b3858;
  border-radius: 3px;
  background: #0b1120;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  color: #dbe5ff;
}

.hero-card-ability img {
  width: 100%;
  height: 100%;
  display: block;
}

.hero-card-ability--disabled {
  opacity: 0.45;
}

.hero-card-compact {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  border: 1px solid #283656;
  border-radius: 6px;
  background: #090e1a;
  padding: 7px 9px;
}

.hero-card-compact-portrait {
  width: 44px;
  height: 44px;
}

.hero-card-compact-meta {
  display: flex;
  flex-direction: column;
  line-height: 1.15;
}

.hero-card-compact-meta strong {
  color: #e5ecff;
  font-size: 0.83rem;
}

.hero-card-compact-meta span {
  color: #98a8cb;
  font-size: 0.74rem;
}

.hero-card-skeleton {
  display: flex;
  align-items: center;
  gap: 10px;
  border: 1px solid #20283e;
  border-radius: 6px;
  background: #090d18;
  padding: 10px;
}

.hero-skeleton-avatar {
  width: 46px;
  height: 46px;
  border-radius: 50%;
  background: linear-gradient(90deg, #171f33 0%, #25304d 50%, #171f33 100%);
  background-size: 180% 100%;
  animation: skeleton-shimmer 1.3s linear infinite;
}

.hero-skeleton-lines {
  display: flex;
  flex-direction: column;
  gap: 5px;
  width: 180px;
}

.hero-skeleton-lines span {
  height: 8px;
  border-radius: 4px;
  background: linear-gradient(90deg, #171f33 0%, #25304d 50%, #171f33 100%);
  background-size: 180% 100%;
  animation: skeleton-shimmer 1.3s linear infinite;
}

.hero-skeleton-lines span:nth-child(1) {
  width: 72%;
}
.hero-skeleton-lines span:nth-child(2) {
  width: 94%;
}
.hero-skeleton-lines span:nth-child(3) {
  width: 62%;
}

@keyframes skeleton-shimmer {
  0% {
    background-position: 0% 0;
  }
  100% {
    background-position: 180% 0;
  }
}

.esc-checkbox {
  position: relative;
  width: 32px;
  height: 32px;
  border: none;
  padding: 0;
  background: transparent;
  cursor: pointer;
  flex-shrink: 0;
}

.esc-checkbox img {
  width: 100%;
  height: 100%;
  display: block;
  position: absolute;
  inset: 0;
}

.esc-radio {
  position: relative;
  width: 24px;
  height: 24px;
  border: none;
  padding: 0;
  background: transparent;
  cursor: pointer;
  flex-shrink: 0;
}

.esc-radio img {
  width: 100%;
  height: 100%;
  display: block;
  position: absolute;
  inset: 0;
}

@media (max-width: 900px) {
  .viewport {
    padding: calc(4vw + 12px) 16px 14px;
  }

  .footer-worker-unit {
    display: none;
  }

  .token-grid {
    gap: 12px;
  }

  .token-grid-header {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 6px 10px;
    margin-bottom: 0;
  }

  .token-grid-header > :first-child {
    display: none;
  }

  .token-faction-label {
    font-size: 0.64rem;
  }

  .token-grid-row {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 8px;
  }

  .token-name {
    grid-column: 1 / -1;
    font-size: 0.92rem;
    text-align: left;
  }

  .token-swatch {
    min-height: 40px;
  }

  .token-hex {
    font-size: 0.78rem;
  }

  .hero-logo {
    width: min(320px, 55vw);
  }

  .bundle-chart-row {
    grid-template-columns: 100px 132px 45px;
  }

  .bundle-chart {
    --bundle-bar-width: 132px;
  }
}

/* Border Textures Gallery */
.borders-category {
  padding: 14px 0 8px;
  border-top: 1px solid rgba(88, 104, 158, 0.45);
}

.borders-category:first-child {
  padding-top: 0;
  border-top: none;
}

.borders-category-title {
  margin: 0 0 2px;
  color: var(--wc3-gold);
  font-size: 0.98rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
}

.borders-category-desc {
  margin: 0 0 10px;
  color: #7b818d;
  font-size: 0.82rem;
  line-height: 1.4;
}

.borders-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
  gap: 12px;
}

.border-item {
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}

.border-thumbnail {
  width: 100%;
  max-width: 156px;
  height: 96px;
  object-fit: contain;
  image-rendering: pixelated;
  background: transparent;
  border-radius: 3px;
}

.border-label {
  color: #e2e9ff;
  font-size: 0.78rem;
  line-height: 1.2;
}

.border-filename {
  color: #5a6080;
  font-size: 0.65rem;
  word-break: break-all;
  line-height: 1.2;
}

.borders-loading {
  color: #7b818d;
  font-size: 0.88rem;
  text-align: center;
  padding: 24px 0;
}

@media (max-width: 640px) {
  .borders-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 10px 8px;
  }

  .border-thumbnail {
    max-width: 132px;
    height: 84px;
  }

  .border-label {
    font-size: 0.74rem;
  }
}

.timer-section {
  text-align: center;
  padding: 2rem;
}
.timer-display {
  font-family: "Friz Quadrata", serif;
  font-size: 4rem;
  color: #fcd312;
  margin: 1rem 0;
  letter-spacing: 0.05em;
}
.timer-controls {
  display: flex;
  gap: 1rem;
  justify-content: center;
  margin-top: 1rem;
}

.build-orders-section {
  max-width: 1100px;
  margin: 0 auto;
  padding: 1.5rem;
}

/* ── Build order list ── */
.build-orders-list {
  display: flex;
  flex-direction: column;
  gap: 2rem;
}

/* ── Per-build card ── */
.build-card {
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: 0;
  background: rgba(0, 0, 0, 0.55);
  border: 1px solid rgba(252, 211, 18, 0.25);
}

/* ── Left column ── */
.build-card-info {
  padding: 1.25rem 1.5rem;
  border-right: 1px solid rgba(252, 211, 18, 0.2);
  display: flex;
  flex-direction: column;
}

.build-card-header {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  margin-bottom: 0.75rem;
}

.build-card-title {
  margin: 0;
  font-size: 1.05rem;
  font-weight: bold;
  color: var(--wc3-gold);
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
  line-height: 1.3;
}

.build-card-subtitle {
  display: flex;
  gap: 0.65rem;
  align-items: center;
  flex-wrap: wrap;
  font-size: 0.72rem;
}

.build-card-matchup {
  margin: 0;
  color: #c8b97a;
  font-style: italic;
}

.build-card-difficulty {
  margin: 0;
  padding: 1px 6px;
  border-radius: 2px;
  font-style: normal;
  font-size: 0.65rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.build-card-difficulty--beginner {
  background: rgba(76, 175, 80, 0.2);
  color: #81c784;
  border: 1px solid rgba(76, 175, 80, 0.35);
}

.build-card-difficulty--intermediate {
  background: rgba(252, 211, 18, 0.12);
  color: var(--wc3-gold);
  border: 1px solid rgba(252, 211, 18, 0.3);
}

.build-card-difficulty--advanced {
  background: rgba(244, 67, 54, 0.15);
  color: #ef9a9a;
  border: 1px solid rgba(244, 67, 54, 0.35);
}

.build-card-body {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  flex: 1;
}

.build-card-desc {
  margin: 0;
  font-size: 0.78rem;
  color: #dbe4ff;
  line-height: 1.55;
}

.build-card-note {
  margin: 0;
  font-size: 0.72rem;
  color: rgba(252, 211, 18, 0.65);
  font-style: italic;
  line-height: 1.5;
  padding-left: 0.5rem;
  border-left: 2px solid rgba(252, 211, 18, 0.2);
}

.build-card-key-timing {
  font-size: 0.75rem;
  color: #c8b97a;
  padding: 0.3rem 0.5rem;
  border: 1px solid rgba(252, 211, 18, 0.2);
  background: rgba(252, 211, 18, 0.05);
  line-height: 1.4;
}

.build-card-key-timing-label {
  color: var(--wc3-gold);
  font-weight: bold;
}

.build-card-timer {
  margin-top: auto;
  padding-top: 0.75rem;
  border-top: 1px solid rgba(252, 211, 18, 0.12);
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.build-card-elapsed {
  font-size: 1.4rem;
  color: var(--wc3-gold);
  text-shadow: 0 0 8px rgba(252, 211, 18, 0.5);
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.05em;
  min-width: 4ch;
}

.build-card-controls {
  display: flex;
  gap: 0.25rem;
  flex-wrap: wrap;
}

/* ── Right column: step table ── */
.build-card-steps {
  padding: 0;
  overflow-x: auto;
  overflow-y: auto;
  max-height: 420px;
}

.build-steps-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  font-size: 0.8rem;
}

.build-steps-table thead tr {
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
}

.build-steps-table th {
  padding: 0.35rem 0.6rem;
  text-align: left;
  color: var(--wc3-gold);
  font-size: 0.68rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: normal;
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
  position: sticky;
  top: 0;
  background: rgba(10, 8, 4, 0.95);
  z-index: 1;
}

.build-steps-table td {
  padding: 0.35rem 0.6rem;
  color: #dbe4ff;
  vertical-align: middle;
}

/* ── Step states ── */
.build-step-row {
  transition: opacity 0.15s ease;
  /* Reserve border space on every row so the active border doesn't shift layout */
  border: 6px solid transparent;
}

.build-step-row--past {
  opacity: 0.4;
}

.build-step-row--active {
  opacity: 1;
  background: rgba(252, 211, 18, 0.06);
}

.build-step-row--active td {
  color: var(--wc3-gold);
  text-shadow: 0 0 6px rgba(252, 211, 18, 0.35);
}

.build-step-order {
  width: 1.8rem;
  color: rgba(252, 211, 18, 0.5);
  font-size: 0.7rem;
  text-align: center;
}

.build-step-time {
  width: 3.5rem;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}

.build-step-instruction {
  /* takes remaining space */
}

.build-step-food {
  width: 4rem;
  white-space: nowrap;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

@media (max-width: 700px) {
  .build-card {
    grid-template-columns: 1fr;
  }

  .build-card-info {
    border-right: none;
    border-bottom: 1px solid rgba(252, 211, 18, 0.2);
  }
}

