}

.chat-input-row {
  display: flex;
  gap: 8px;
}

.chat-input-row input {
  flex: 1;
  border: 1px solid #2a3453;
  border-radius: 4px;
  background: #0a0f1c;
  color: #dce5fb;
  font-family: inherit;
  padding: 7px 9px;
