  padding: 7px 12px;
}

.hero-card-stack {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.hero-card-preview {
  display: flex;
  gap: 12px;
  align-items: flex-start;
  border: 1px solid #2a3554;
  border-radius: 6px;
  background: linear-gradient(180deg, #0d1323 0%, #080d1a 100%);
  padding: 12px;
}

.hero-card-portrait-wrap {
