}

.hero-card-portrait {
  width: 78px;
  height: 78px;
}

.hero-card-level {
  position: absolute;
  right: -6px;
  bottom: -4px;
  min-width: 20px;
  padding: 1px 5px;
  border: 1px solid rgba(255, 212, 18, 0.58);
  border-radius: 10px;
  background: rgba(0, 0, 0, 0.8);
