    background-position: 0% 0;
  }
  100% {
    background-position: 180% 0;
  }
}

.esc-checkbox {
  position: relative;
  width: 32px;
  height: 32px;
  border: none;
  padding: 0;
  background: transparent;
  cursor: pointer;
