  font-family: "Friz Quadrata", serif;
  font-size: 4rem;
  color: #fcd312;
  margin: 1rem 0;
  letter-spacing: 0.05em;
}
.timer-controls {
  display: flex;
  gap: 1rem;
  justify-content: center;
  margin-top: 1rem;
}

.build-orders-section {
  max-width: 1100px;
  margin: 0 auto;
  padding: 1.5rem;
}

/* ── Build order toolbar ── */
.build-orders-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  margin-bottom: 1rem;
  flex-wrap: wrap;
}

.build-orders-toolbar h3 {
  margin: 0;
  white-space: nowrap;
}

.build-orders-toolbar-actions {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex: 1;
  justify-content: flex-end;
  min-width: 0;
}

.build-orders-toolbar-actions .popup-trigger-anchor {
  width: auto;
  min-width: 220px;
  max-width: 420px;
  flex: 1;
}

.build-orders-toolbar-actions .popup-trigger-button {
  width: 100%;
}

.build-orders-toolbar-actions .popup-menu-demo {
  width: 100%;
}

.build-import-input {
  display: none;
}

.build-import-status {
  font-size: 0.78rem;
  color: var(--wc3-gold);
  padding: 0.3rem 0.6rem;
  margin-bottom: 0.75rem;
  background: rgba(252, 211, 18, 0.08);
  border: 1px solid rgba(252, 211, 18, 0.2);
}

.build-card-empty {
  text-align: center;
  color: rgba(252, 211, 18, 0.6);
  padding: 2rem 0;
}

/* ── Per-build card ── */
.build-card {
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: 0;
  background: rgba(0, 0, 0, 0.55);
  border: 1px solid rgba(252, 211, 18, 0.25);
}

/* ── Left column ── */
.build-card-info {
  padding: 1.25rem 1.5rem;
  border-right: 1px solid rgba(252, 211, 18, 0.2);
  display: flex;
  flex-direction: column;
}

.build-card-header {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  margin-bottom: 0.75rem;
}

.build-card-title {
  margin: 0;
  font-size: 1.05rem;
  font-weight: bold;
  color: var(--wc3-gold);
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
  line-height: 1.3;
}

.build-card-subtitle {
  display: flex;
  gap: 0.65rem;
  align-items: center;
  flex-wrap: wrap;
  font-size: 0.72rem;
}

.build-card-matchup {
  margin: 0;
  color: #c8b97a;
  font-style: italic;
}

.build-card-difficulty {
  margin: 0;
  padding: 1px 6px;
  border-radius: 2px;
  font-style: normal;
  font-size: 0.65rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.build-card-difficulty--beginner {
  background: rgba(76, 175, 80, 0.2);
  color: #81c784;
  border: 1px solid rgba(76, 175, 80, 0.35);
}

.build-card-difficulty--intermediate {
  background: rgba(252, 211, 18, 0.12);
  color: var(--wc3-gold);
  border: 1px solid rgba(252, 211, 18, 0.3);
}

.build-card-difficulty--advanced {
  background: rgba(244, 67, 54, 0.15);
  color: #ef9a9a;
  border: 1px solid rgba(244, 67, 54, 0.35);
}

.build-card-body {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  flex: 1;
}

.build-card-desc {
  margin: 0;
  font-size: 0.78rem;
  color: #dbe4ff;
  line-height: 1.55;
}

.build-card-note {
  margin: 0;
  font-size: 0.72rem;
  color: rgba(252, 211, 18, 0.65);
  font-style: italic;
  line-height: 1.5;
  padding-left: 0.5rem;
  border-left: 2px solid rgba(252, 211, 18, 0.2);
}

.build-card-key-timing {
  font-size: 0.75rem;
  color: #c8b97a;
  padding: 0.3rem 0.5rem;
  border: 1px solid rgba(252, 211, 18, 0.2);
  background: rgba(252, 211, 18, 0.05);
  line-height: 1.4;
}

.build-card-key-timing-label {
  color: var(--wc3-gold);
  font-weight: bold;
}

.build-card-timer {
  margin-top: auto;
  padding-top: 0.75rem;
  border-top: 1px solid rgba(252, 211, 18, 0.12);
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.build-card-elapsed {
  font-size: 1.4rem;
  color: var(--wc3-gold);
  text-shadow: 0 0 8px rgba(252, 211, 18, 0.5);
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.05em;
  min-width: 4ch;
}

.build-card-controls {
  display: flex;
  gap: 0.25rem;
  flex-wrap: wrap;
}

/* ── Right column: step table ── */
.build-card-steps {
  padding: 0;
  overflow-x: auto;
  overflow-y: auto;
  max-height: 420px;
}

.build-steps-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  font-size: 0.8rem;
}

.build-steps-table thead tr {
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
}

.build-steps-table th {
  padding: 0.35rem 0.6rem;
  text-align: left;
  color: var(--wc3-gold);
  font-size: 0.68rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: normal;
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
  position: sticky;
  top: 0;
  background: rgba(10, 8, 4, 0.95);
  z-index: 1;
}

.build-steps-table td {
  padding: 0.35rem 0.6rem;
  color: #dbe4ff;
  vertical-align: middle;
}

/* ── Step states ── */
.build-step-row {
  transition: opacity 0.15s ease;
  /* Reserve border space on every row so the active border doesn't shift layout */
  border: 6px solid transparent;
}

.build-step-row--past {
  opacity: 0.4;
}

.build-step-row--active {
  opacity: 1;
  background: rgba(252, 211, 18, 0.06);
}

.build-step-row--active td {
  color: var(--wc3-gold);
  text-shadow: 0 0 6px rgba(252, 211, 18, 0.35);
}

.build-step-order {
  width: 1.8rem;
  color: rgba(252, 211, 18, 0.5);
  font-size: 0.7rem;
  text-align: center;
}

.build-step-time {
  width: 3.5rem;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}

.build-step-instruction {
  /* takes remaining space */
}

.build-step-food {
  width: 4rem;
  white-space: nowrap;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

@media (max-width: 700px) {
  .build-card {
    grid-template-columns: 1fr;
  }

  .build-card-info {
    border-right: none;
    border-bottom: 1px solid rgba(252, 211, 18, 0.2);
  }
}

