  1→import { useEffect, useRef } from 'react';
  2→import { ModelRenderer, decodeBLP, getBLPImageData, parseMDX } from 'war3-model';
  3→import { mat3, mat4, quat, vec3 } from 'gl-matrix';
  4→import type { Race } from '../lib/types';
  5→
  6→type ModelType = ReturnType<typeof parseMDX>;
  7→
  8→interface HeroPortraitConfig {
  9→  modelPath: string;
 10→  textures: Record<string, string>;
 11→}
 12→
 13→const HERO_PORTRAIT_CONFIG: Record<Race, HeroPortraitConfig> = {
 14→  Human: {
 15→    modelPath: '/models/hero-portrait/Human/HeroArchMage_portrait.mdx',
 16→    textures: { 'heroarchmage.blp': '/models/hero-portrait/textures/Human/HeroArchmage.blp' },
 17→  },
 18→  Orc: {
 19→    modelPath: '/models/hero-portrait/Orc/HeroBladeMaster_portrait.mdx',
 20→    textures: { 'heroblademaster.blp': '/models/hero-portrait/textures/Orc/HeroBladeMaster.blp' },
 21→  },
 22→  NightElf: {
 23→    modelPath: '/models/hero-portrait/NightElf/HeroDemonHunter_Portrait.mdx',
 24→    textures: {
 25→      'herodemonhunter.blp': '/models/hero-portrait/textures/NightElf/HeroDemonHunter.blp',
 26→      'black32.blp': '/models/hero-portrait/textures/NightElf/Black32.blp',
 27→    },
 28→  },
 29→  Undead: {
 30→    modelPath: '/models/hero-portrait/Undead/HeroDeathKnight_portrait.mdx',
 31→    textures: { 'herodeathknight.blp': '/models/hero-portrait/textures/Undead/HeroDeathknight.blp' },
 32→  },
 33→};
 34→
 35→const modelCache = new Map<string, ModelType>();
 36→const blpCache = new Map<string, ImageData[]>();
 37→
 38→function normalizeTextureName(textureImage: string): string {
 39→  const normalized = textureImage.replaceAll('\\', '/');
 40→  const lastSlash = normalized.lastIndexOf('/');
 41→  return (lastSlash >= 0 ? normalized.slice(lastSlash + 1) : normalized).toLowerCase();
 42→}
 43→
 44→function getTexturePath(textureImage: string, race: Race): string | null {
 45→  const key = normalizeTextureName(textureImage);
 46→  const raceTexture = HERO_PORTRAIT_CONFIG[race].textures[key];
 47→  if (raceTexture) return raceTexture;
 48→  if (key.startsWith('teamcolor')) return '/models/hero-portrait/textures/shared/TeamColor00.blp';
 49→  if (key.startsWith('teamglow')) return '/models/hero-portrait/textures/shared/TeamGlow00.blp';
 50→  return null;
 51→}
 52→
 53→async function loadModel(race: Race): Promise<ModelType> {
 54→  const path = HERO_PORTRAIT_CONFIG[race].modelPath;
 55→  const cached = modelCache.get(path);
 56→  if (cached) return cached;
 57→  const res = await fetch(path);
 58→  if (!res.ok) throw new Error(`Failed to load hero portrait model: ${path}`);
 59→  const ab = await res.arrayBuffer();
 60→  const model = parseMDX(ab);
 61→  modelCache.set(path, model);
 62→  return model;
 63→}
 64→
 65→async function loadBLPMips(path: string): Promise<ImageData[]> {
 66→  const cached = blpCache.get(path);
 67→  if (cached) return cached;
 68→  const res = await fetch(path);
 69→  if (!res.ok) throw new Error(`Failed to load hero portrait texture: ${path}`);
 70→  const ab = await res.arrayBuffer();
 71→  const blp = decodeBLP(ab);
 72→  const mips: ImageData[] = [];
 73→  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
 74→  for (let i = 0; i < maxLevels; i++) {
 75→    const w = blp.width >> i;
 76→    const h = blp.height >> i;
 77→    if (w <= 0 || h <= 0) break;
 78→    try {
 79→      const img = getBLPImageData(blp, i);
 80→      if (!img || !img.width || !img.height) break;
 81→      mips.push(new ImageData(new Uint8ClampedArray(img.data), img.width, img.height));
 82→      if (img.width === 1 && img.height === 1) break;
 83→    } catch { break; }
 84→  }
 85→  if (mips.length === 0) throw new Error(`No mip levels decoded for hero portrait texture: ${path}`);
 86→  blpCache.set(path, mips);
 87→  return mips;
 88→}
 89→
 90→function findPortraitSequenceIndex(model: ModelType): number {
 91→  const sequences = model.Sequences || [];
 92→  if (sequences.length === 0) return 0;
 93→  const byName = (predicate: (name: string) => boolean) =>
 94→    sequences.findIndex((seq) => predicate((seq.Name || '').toLowerCase()));
 95→  let idx = byName((name) => name.includes('portrait') && !name.includes('talk'));
 96→  if (idx >= 0) return idx;
 97→  idx = byName((name) => name.includes('stand'));
 98→  if (idx >= 0) return idx;
 99→  idx = byName((name) => name.includes('portrait'));
100→  if (idx >= 0) return idx;
101→  return 0;
102→}
103→
104→interface HeroPortraitModelProps {
105→  race: Race;
106→}
107→
108→export default function HeroPortraitModel(props: HeroPortraitModelProps) {
109→  const canvasRef = useRef<HTMLCanvasElement>(null);
110→  const stateRef = useRef({
111→    gl: null as WebGLRenderingContext | WebGL2RenderingContext | null,
112→    modelRenderer: null as ModelRenderer | null,
113→    resizeObserver: null as ResizeObserver | null,
114→    rafId: 0,
115→    disposed: false,
116→    initVersion: 0,
117→    mvMatrix: mat4.create(),
118→    pMatrix: mat4.create(),
119→    worldCameraMatrix: mat4.create(),
120→    cameraPos: vec3.create(),
121→    cameraTarget: vec3.create(),
122→    cameraQuat: quat.create(),
123→    cameraFov: 0.691111,
124→    cameraNear: 8,
125→    cameraFar: 1800,
126→  });
127→
128→  useEffect(() => {
129→    const s = stateRef.current;
130→    const canvas = canvasRef.current!;
131→
132→    const destroyRenderer = () => {
133→      if (!s.modelRenderer) return;
134→      try { s.modelRenderer.destroy(); } catch (err) { console.warn('hero portrait renderer destroy failed', err); }
135→      finally { s.modelRenderer = null; }
136→    };
137→
138→    const updateProjection = () => {
139→      const aspect = Math.max(1e-6, canvas.clientWidth / Math.max(1, canvas.clientHeight));
140→      mat4.perspective(s.pMatrix, s.cameraFov, aspect, s.cameraNear, s.cameraFar);
141→    };
142→
143→    const resizeCanvas = () => {
144→      if (!s.gl) return;
145→      const dpr = window.devicePixelRatio || 1;
146→      const w = Math.max(1, Math.round(canvas.clientWidth * dpr));
147→      const h = Math.max(1, Math.round(canvas.clientHeight * dpr));
148→      if (canvas.width !== w || canvas.height !== h) { canvas.width = w; canvas.height = h; }
149→      s.gl.viewport(0, 0, w, h);
150→      updateProjection();
151→    };
152→
153→    const configureCamera = (model: ModelType) => {
154→      const cam = model.Cameras?.[0];
155→      if (cam) {
156→        vec3.set(s.cameraPos, cam.Position[0], cam.Position[1], cam.Position[2]);
157→        vec3.set(s.cameraTarget, cam.TargetPosition[0], cam.TargetPosition[1], cam.TargetPosition[2]);
158→        s.cameraFov = Math.max(0.35, cam.FieldOfView || 0.691111);
159→        s.cameraNear = Math.max(4, cam.NearClip || 8);
160→        s.cameraFar = Math.max(s.cameraNear + 100, cam.FarClip || 1800);
161→        mat4.lookAt(s.mvMatrix, s.cameraPos, s.cameraTarget, vec3.fromValues(0, 0, 1));
162→      } else {
163→        const min = model.Info?.MinimumExtent;
164→        const max = model.Info?.MaximumExtent;
165→        if (min && max) {
166→          const cx = (min[0] + max[0]) * 0.5, cy = (min[1] + max[1]) * 0.5, cz = (min[2] + max[2]) * 0.5;
167→          const radius = Math.max(140, model.Info?.BoundsRadius || 180);
168→          vec3.set(s.cameraPos, cx + radius * 0.2, cy - radius * 1.8, cz + radius * 0.2);
169→          vec3.set(s.cameraTarget, cx, cy, cz);
170→        } else {
171→          vec3.set(s.cameraPos, 0, -450, 120);
172→          vec3.set(s.cameraTarget, 0, 0, 110);
173→        }
174→        s.cameraFov = 0.691111; s.cameraNear = 8; s.cameraFar = 1800;
175→        mat4.lookAt(s.mvMatrix, s.cameraPos, s.cameraTarget, vec3.fromValues(0, 0, 1));
176→      }
177→      if (mat4.invert(s.worldCameraMatrix, s.mvMatrix)) {
178→        const rot = mat3.create();
179→        mat3.fromMat4(rot, s.worldCameraMatrix);
180→        quat.fromMat3(s.cameraQuat, rot);
181→        quat.normalize(s.cameraQuat, s.cameraQuat);
182→      } else { quat.identity(s.cameraQuat); }
183→    };
184→
185→    const startRenderLoop = () => {
186→      let lastTs = performance.now();
187→      const tick = (now: number) => {
188→        if (s.disposed) return;
189→        s.rafId = requestAnimationFrame(tick);
190→        if (!s.gl || !s.modelRenderer) return;
191→        resizeCanvas();
192→        const delta = Math.min(100, now - lastTs);
193→        lastTs = now;
194→        s.modelRenderer.update(delta);
195→        s.gl.clearColor(0, 0, 0, 0);
196→        s.gl.clear(s.gl.COLOR_BUFFER_BIT | s.gl.DEPTH_BUFFER_BIT);
197→        s.modelRenderer.render(s.mvMatrix, s.pMatrix, { env: false, wireframe: false });
198→      };
199→      s.rafId = requestAnimationFrame(tick);
200→    };
201→
202→    const initForRace = async (race: Race) => {
203→      const version = ++s.initVersion;
204→      const model = await loadModel(race);
205→      if (s.disposed || version !== s.initVersion || !s.gl) return;
206→      destroyRenderer();
207→      s.modelRenderer = new ModelRenderer(model);
208→      s.modelRenderer.initGL(s.gl);
209→      configureCamera(model);
210→      s.modelRenderer.setCamera(s.cameraPos, s.cameraQuat);
211→      s.modelRenderer.setLightPosition(s.cameraPos);
212→      s.modelRenderer.setLightColor(vec3.fromValues(1, 1, 1));
213→      s.modelRenderer.setSequence(findPortraitSequenceIndex(model));
214→      const texturePromises = (model.Textures || []).map(async (tex) => {
215→        const texturePath = getTexturePath(tex.Image, race);
216→        if (!texturePath) return;
217→        const mips = await loadBLPMips(texturePath);
218→        if (!s.disposed && version === s.initVersion) s.modelRenderer!.setTextureImageData(tex.Image, mips);
219→      });
220→      await Promise.all(texturePromises);
221→    };
222→
223→    // Store initForRace for race-change effect
224→    (s as any).initForRace = initForRace;
225→
226→    s.gl = canvas.getContext('webgl2', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false }) as WebGL2RenderingContext | null;
227→    if (!s.gl) s.gl = canvas.getContext('webgl', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false });
228→    if (!s.gl) return;
229→
230→    resizeCanvas();
231→    s.resizeObserver = new ResizeObserver(() => resizeCanvas());
232→    s.resizeObserver.observe(canvas);
233→    startRenderLoop();
234→    void initForRace(props.race).catch((err) => console.error(err));
235→
236→    return () => {
237→      s.disposed = true;
238→      s.initVersion++;
239→      cancelAnimationFrame(s.rafId);
240→      s.resizeObserver?.disconnect();
241→      destroyRenderer();
242→    };
243→  }, []);
244→
245→  useEffect(() => {
246→    const s = stateRef.current;
247→    if (!s.gl || s.disposed) return;
248→    const initForRace = (s as any).initForRace as ((race: Race) => Promise<void>) | undefined;
249→    if (initForRace) void initForRace(props.race).catch((err) => console.error(err));
250→  }, [props.race]);
251→
252→  return (
