.footer-links a {
  color: var(--wc3-dark-gold);
  text-decoration: none;
}

.footer-links a:hover {
  color: var(--wc3-gold);
  text-decoration: underline;
}

.footer-joke {
  margin: 0;
  color: #3a3f54;
  font-size: 0.78rem;
}

.footer-signoff {
  margin: 2rem 0 0;
  color: #7b818d;
  font-size: 0.85rem;
}

.resource-counter {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 1rem;
  color: #eceff7;
  text-shadow:
    0 1px 2px #000,
    0 0 2px #000;
  white-space: nowrap;
}

.resource-counter img {
  width: 20px;
  height: 20px;
  image-rendering: pixelated;
}

/* Command Card (Hotkey) Buttons */
@property --sweep {
  syntax: "<angle>";
  inherits: false;
  initial-value: 360deg;
}

.cmd-btn {
  position: relative;
  width: 48px;
  height: 48px;
  border: none;
  border-radius: 0;
  overflow: hidden;
  cursor: pointer;
  padding: 0;
  background: transparent;
  flex-shrink: 0;
  color: #f0d775;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

.cmd-btn--showcase {
  width: 64px;
  height: 64px;
}

.cmd-btn:focus-visible {
  outline: 1px solid #f0d775;
  outline-offset: 1px;
}

.cmd-btn:disabled {
  cursor: default;
}

.cmd-btn img {
  image-rendering: pixelated;
}

.cmd-btn-backdrop,
.cmd-btn-icon,
.cmd-btn-frame {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  pointer-events: none;
}

.cmd-btn-backdrop {
  z-index: 1;
}

.cmd-btn-icon {
  z-index: 2;
}

.cmd-btn-frame {
  z-index: 3;
}

.cmd-btn-highlight {
  position: absolute;
  inset: 0;
  background-size: 100% 100%;
  mix-blend-mode: screen;
  opacity: 0;
  transition: opacity 80ms linear;
  pointer-events: none;
  z-index: 4;
}

.cmd-btn:hover .cmd-btn-highlight,
.cmd-btn-highlight.cmd-btn-highlight--on {
  opacity: 1;
}

.cmd-btn--pressed img {
  filter: brightness(0.7);
}

.cmd-btn--pressed {
  transform: translate(1px, 1px);
}

.cmd-btn-hotkey {
  position: absolute;
  right: 2px;
  bottom: 2px;
  font-size: 0.62rem;
  font-weight: 700;
  line-height: 1;
  color: #f0d775;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
  user-select: none;
  z-index: 5;
}

@keyframes cooldown-sweep {
  from {
    --sweep: 360deg;
  }
  to {
    --sweep: 0deg;
  }
}

.cmd-btn-cooldown {
  position: absolute;
  inset: 0;
  background: conic-gradient(
    from 0deg,
    rgba(0, 0, 0, 0.75) var(--sweep),
    transparent var(--sweep)
  );
  animation: cooldown-sweep 8s linear infinite;
  pointer-events: none;
  z-index: 6;
}

.cmd-btn-no-resources {
  position: absolute;
  inset: 0;
  background: rgba(255, 40, 40, 0.35);
  pointer-events: none;
  z-index: 6;
}

.cmd-btn--no-resources .cmd-btn-hotkey {
  color: #ffb3b3;
}

.command-card-preview {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.command-card-grid {
  display: grid;
  grid-template-columns: repeat(4, 64px);
  grid-template-rows: repeat(3, 64px);
  gap: 8px;
  padding: 0;
}

.command-card-cell {
  width: 64px;
  height: 64px;
}

.command-card-cell .cmd-btn {
  width: 100%;
  height: 100%;
}

.command-card-cell .cmd-btn-hotkey {
  right: 3px;
  bottom: 3px;
  font-size: 0.78rem;
}

.cmd-btn-fallback-icon {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #dbe5ff;
  background: radial-gradient(
    circle at 35% 30%,
    #2f4f96 0%,
    #112342 60%,
    #090f1e 100%
  );
  font-size: 1.05rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
  pointer-events: none;
  z-index: 2;
}

.cmd-btn-empty {
  cursor: default;
  background-color: #020308;
}

.cmd-btn--passive .cmd-btn-icon {
  filter: saturate(0.72) brightness(0.88);
}

.cmd-btn--levelup .cmd-btn-icon {
  filter: saturate(1.1) brightness(1.08);
}

.cmd-btn--levelup .cmd-btn-hotkey {
  color: #ffd843;
}

.unit-queue-preview {
  display: flex;
  justify-content: center;
}

.unit-queue-stage {
  position: relative;
  width: min(100%, 482px);
  aspect-ratio: 241 / 93;
}

.unit-queue-canvas,
.unit-queue-fallback {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
}

.unit-queue-canvas {
  image-rendering: auto;
}

.unit-queue-fallback {
  border: 1px solid #1f2636;
  border-radius: 6px;
  background-color: #070912;
}

.tooltip-preview-grid {
  display: grid;
  gap: 10px;
  justify-items: start;
}

/* WC3 data refs: MiscUI ToolTip* font heights = 0.011, InfoPanel gold text ~ #fcd312. */
.tooltip-preview {
  position: relative;
  width: min(100%, 384px);
  border: 10px solid transparent;
  border-color: rgba(244, 212, 94, 0.35);
  border-image: var(--tooltip-border) 33.333% fill / 10px;
  background-color: #0a0d16;
  background-image: var(--tooltip-bg);
  background-repeat: repeat;
  background-size: auto;
  padding: 10px 12px;
  color: #f4f7ff;
}

.tooltip-preview--simple {
  width: min(100%, 340px);
}

.tooltip-preview--error {
  color: #eec9c9;
}

.tooltip-preview-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.tooltip-preview-head h4 {
  margin: 0;
  color: var(--wc3-gold);
  font-size: 0.72rem;
  line-height: 1.2;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.85);
}

.tooltip-preview p {
  margin: 6px 0 0;
  color: #f1f5ff;
  font-size: 0.72rem;
  line-height: 1.35;
}

.tooltip-hotkey {
  padding: 0;
  color: #fed312;
  font-family: inherit;
  font-size: 0.72rem;
  letter-spacing: 0.01em;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.85);
}

.tooltip-costs {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 8px;
}

.tooltip-cost {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  color: #ffffff;
  font-size: 0.72rem;
}

.tooltip-cost img {
  width: 14px;
  height: 14px;
  image-rendering: pixelated;
}

.portrait-showcase {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.portrait-stage-wrap {
  position: relative;
  width: min(225px, 52vw);
}

.portrait-stage {
  position: relative;
  width: 100%;
  aspect-ratio: 130 / 160;
  image-rendering: pixelated;
  z-index: 2;
}

.portrait-window {
  position: absolute;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  -webkit-mask-image: var(--portrait-window-mask);
  mask-image: var(--portrait-window-mask);
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-size: 100% 100%;
  mask-size: 100% 100%;
  -webkit-mask-position: center;
  mask-position: center;
  overflow: hidden;
  background: #000;
  z-index: 1;
}

.portrait-frame-overlay {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: fill;
  pointer-events: none;
  z-index: 2;
}

.minimap-showcase {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
}

.minimap-frame {
  position: relative;
  width: 220px;
  height: 220px;
  overflow: hidden;
  border: 2px solid #2a3555;
  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.06);
  background: #090d17;
}

.minimap-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  opacity: 0.78;
}

.minimap-fog {
  position: absolute;
  inset: 0;
  background: radial-gradient(
    circle at 50% 50%,
    rgba(0, 0, 0, 0) 32%,
    rgba(0, 0, 0, 0.68) 100%
  );
  pointer-events: none;
}

.minimap-ping {
  position: absolute;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.75);
  box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.45);
  animation: minimap-ping 1.8s ease-out infinite;
}

.minimap-ping--a {
  left: 26%;
  top: 34%;
  background: #58d869;
}

.minimap-ping--b {
  left: 61%;
  top: 54%;
  background: #e65a5a;
  animation-delay: 0.6s;
}

.minimap-ping--c {
  left: 47%;
  top: 20%;
  background: #f0d775;
  animation-delay: 1.1s;
}

@keyframes minimap-ping {
  0% {
    box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.45);
  }
  100% {
    box-shadow: 0 0 0 12px rgba(255, 255, 255, 0);
  }
}

.minimap-legend {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  justify-content: center;
  color: #9ca8c5;
  font-size: 0.76rem;
}

.minimap-legend span {
  display: inline-flex;
  align-items: center;
  gap: 5px;
}

.dot {
  width: 8px;
