  font-size: 1rem;
}

.hero-card-head span {
  color: #9cabcf;
  font-size: 0.78rem;
}

.hero-card-bars {
  margin-top: 8px;
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.hero-card-bar {
  position: relative;
  height: 12px;
  border: 1px solid #2f3f68;
  border-radius: 3px;
  background: #070b14;
  overflow: hidden;
}

.hero-card-bar-fill {
  position: absolute;
  inset: 0 auto 0 0;
  height: 100%;
}

.hero-card-bar-fill--hp {
  background: linear-gradient(90deg, #3abf3a 0%, #58d869 100%);
}

.hero-card-bar-fill--mp {
  background: linear-gradient(90deg, #3a58d2 0%, #6280ff 100%);
}

.hero-card-bar span {
  position: relative;
  display: block;
  text-align: center;
  color: #ecf1ff;
  font-size: 0.66rem;
  line-height: 10px;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.hero-card-stats {
  margin-top: 8px;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 4px 10px;
  color: #b4c0dd;
  font-size: 0.73rem;
}

.hero-card-stats b {
  color: #e0e8ff;
  font-weight: 700;
}

.hero-card-abilities {
  margin-top: 9px;
  display: flex;
  gap: 6px;
}

.hero-card-ability {
  width: 30px;
  height: 30px;
  border: 1px solid #2b3858;
  border-radius: 3px;
  background: #0b1120;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  color: #dbe5ff;
}

.hero-card-ability img {
  width: 100%;
  height: 100%;
  display: block;
}

.hero-card-ability--disabled {
  opacity: 0.45;
}

.hero-card-compact {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  border: 1px solid #283656;
  border-radius: 6px;
  background: #090e1a;
  padding: 7px 9px;
}

.hero-card-compact-portrait {
  width: 44px;
  height: 44px;
}

.hero-card-compact-meta {
  display: flex;
  flex-direction: column;
  line-height: 1.15;
}

.hero-card-compact-meta strong {
  color: #e5ecff;
  font-size: 0.83rem;
}

.hero-card-compact-meta span {
  color: #98a8cb;
  font-size: 0.74rem;
}

.hero-card-skeleton {
  display: flex;
  align-items: center;
  gap: 10px;
  border: 1px solid #20283e;
  border-radius: 6px;
  background: #090d18;
  padding: 10px;
}

.hero-skeleton-avatar {
  width: 46px;
  height: 46px;
  border-radius: 50%;
  background: linear-gradient(90deg, #171f33 0%, #25304d 50%, #171f33 100%);
  background-size: 180% 100%;
  animation: skeleton-shimmer 1.3s linear infinite;
}

.hero-skeleton-lines {
  display: flex;
  flex-direction: column;
  gap: 5px;
  width: 180px;
}

.hero-skeleton-lines span {
  height: 8px;
  border-radius: 4px;
  background: linear-gradient(90deg, #171f33 0%, #25304d 50%, #171f33 100%);
  background-size: 180% 100%;
  animation: skeleton-shimmer 1.3s linear infinite;
}

.hero-skeleton-lines span:nth-child(1) {
  width: 72%;
}
.hero-skeleton-lines span:nth-child(2) {
  width: 94%;
}
.hero-skeleton-lines span:nth-child(3) {
  width: 62%;
}

@keyframes skeleton-shimmer {
  0% {
    background-position: 0% 0;
  }
  100% {
    background-position: 180% 0;
  }
}

.esc-checkbox {
  position: relative;
  width: 32px;
  height: 32px;
  border: none;
  padding: 0;
  background: transparent;
  cursor: pointer;
  flex-shrink: 0;
}

.esc-checkbox img {
  width: 100%;
  height: 100%;
  display: block;
  position: absolute;
  inset: 0;
}

.esc-radio {
  position: relative;
  width: 24px;
  height: 24px;
  border: none;
  padding: 0;
  background: transparent;
  cursor: pointer;
  flex-shrink: 0;
}

.esc-radio img {
  width: 100%;
  height: 100%;
  display: block;
  position: absolute;
  inset: 0;
}

@media (max-width: 900px) {
  .viewport {
    padding: calc(4vw + 12px) 16px 14px;
  }

  .footer-worker-unit {
    display: none;
  }

  .token-grid {
    gap: 12px;
  }

  .token-grid-header {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 6px 10px;
    margin-bottom: 0;
  }

  .token-grid-header > :first-child {
    display: none;
  }

  .token-faction-label {
    font-size: 0.64rem;
  }

  .token-grid-row {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 8px;
  }

  .token-name {
    grid-column: 1 / -1;
    font-size: 0.92rem;
    text-align: left;
  }

  .token-swatch {
    min-height: 40px;
  }

  .token-hex {
    font-size: 0.78rem;
  }

  .hero-logo {
    width: min(320px, 55vw);
  }

  .bundle-chart-row {
    grid-template-columns: 100px 132px 45px;
  }

  .bundle-chart {
    --bundle-bar-width: 132px;
  }
}

/* Border Textures Gallery */
.borders-category {
  padding: 14px 0 8px;
  border-top: 1px solid rgba(88, 104, 158, 0.45);
}

.borders-category:first-child {
  padding-top: 0;
  border-top: none;
}

.borders-category-title {
  margin: 0 0 2px;
  color: var(--wc3-gold);
  font-size: 0.98rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
}

.borders-category-desc {
  margin: 0 0 10px;
  color: #7b818d;
  font-size: 0.82rem;
  line-height: 1.4;
}

.borders-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
  gap: 12px;
}

.border-item {
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}

.border-thumbnail {
  width: 100%;
  max-width: 156px;
  height: 96px;
  object-fit: contain;
  image-rendering: pixelated;
  background: transparent;
  border-radius: 3px;
}

.border-label {
  color: #e2e9ff;
  font-size: 0.78rem;
  line-height: 1.2;
}

.border-filename {
  color: #5a6080;
  font-size: 0.65rem;
  word-break: break-all;
  line-height: 1.2;
}

.borders-loading {
  color: #7b818d;
  font-size: 0.88rem;
  text-align: center;
  padding: 24px 0;
}

@media (max-width: 640px) {
  .borders-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 10px 8px;
  }

  .border-thumbnail {
    max-width: 132px;
    height: 84px;
  }

  .border-label {
    font-size: 0.74rem;
  }
}

.timer-section {
  text-align: center;
  padding: 2rem;
}
.timer-display {
  font-family: "Friz Quadrata", serif;
  font-size: 4rem;
  color: #fcd312;
  margin: 1rem 0;
  letter-spacing: 0.05em;
}
.timer-controls {
  display: flex;
  gap: 1rem;
  justify-content: center;
  margin-top: 1rem;
}

.build-orders-section {
  max-width: 1100px;
  margin: 0 auto;
  padding: 1.5rem;
}

/* ── Build order toolbar ── */
.build-orders-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  margin-bottom: 1rem;
  flex-wrap: wrap;
}

.build-orders-toolbar h3 {
  margin: 0;
  white-space: nowrap;
}

.build-orders-toolbar-actions {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex: 1;
  justify-content: flex-end;
  min-width: 0;
}

.build-orders-toolbar-actions .popup-trigger-anchor {
  width: auto;
  min-width: 220px;
  max-width: 420px;
  flex: 1;
}

.build-orders-toolbar-actions .popup-trigger-button {
  width: 100%;
  height: 40px;
}

.build-orders-toolbar-actions .popup-menu-demo {
  width: 100%;
}

.build-orders-toolbar-actions .glue-screen-button {
  width: 120px;
  height: 40px;
  font-size: 0.84rem;
}

.build-import-input {
  display: none;
}

.build-import-status {
  font-size: 0.78rem;
  color: var(--wc3-gold);
  padding: 0.3rem 0.6rem;
  margin-bottom: 0.75rem;
  background: rgba(252, 211, 18, 0.08);
  border: 1px solid rgba(252, 211, 18, 0.2);
}

.build-card-empty {
  text-align: center;
  color: rgba(252, 211, 18, 0.6);
  padding: 2rem 0;
}

/* ── Per-build card ── */
.build-card {
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: 0;
  background: rgba(0, 0, 0, 0.55);
  border: 1px solid rgba(252, 211, 18, 0.25);
}

/* ── Left column ── */
.build-card-info {
  padding: 1.25rem 1.5rem;
  border-right: 1px solid rgba(252, 211, 18, 0.2);
  display: flex;
  flex-direction: column;
}

.build-card-header {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  margin-bottom: 0.75rem;
}

.build-card-title {
  margin: 0;
  font-size: 1.05rem;
  font-weight: bold;
  color: var(--wc3-gold);
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
  line-height: 1.3;
}

.build-card-subtitle {
  display: flex;
  gap: 0.65rem;
  align-items: center;
  flex-wrap: wrap;
  font-size: 0.72rem;
}

.build-card-matchup {
  margin: 0;
  color: #c8b97a;
  font-style: italic;
}

.build-card-difficulty {
  margin: 0;
  padding: 1px 6px;
  border-radius: 2px;
  font-style: normal;
  font-size: 0.65rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.build-card-difficulty--beginner {
  background: rgba(76, 175, 80, 0.2);
  color: #81c784;
  border: 1px solid rgba(76, 175, 80, 0.35);
}

.build-card-difficulty--intermediate {
  background: rgba(252, 211, 18, 0.12);
  color: var(--wc3-gold);
  border: 1px solid rgba(252, 211, 18, 0.3);
}

.build-card-difficulty--advanced {
  background: rgba(244, 67, 54, 0.15);
  color: #ef9a9a;
  border: 1px solid rgba(244, 67, 54, 0.35);
}

.build-card-body {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  flex: 1;
}

.build-card-desc {
  margin: 0;
  font-size: 0.78rem;
  color: #dbe4ff;
  line-height: 1.55;
}

.build-card-note {
  margin: 0;
  font-size: 0.72rem;
  color: rgba(252, 211, 18, 0.65);
  font-style: italic;
  line-height: 1.5;
  padding-left: 0.5rem;
  border-left: 2px solid rgba(252, 211, 18, 0.2);
}

.build-card-key-timing {
  font-size: 0.75rem;
  color: #c8b97a;
  padding: 0.3rem 0.5rem;
  border: 1px solid rgba(252, 211, 18, 0.2);
  background: rgba(252, 211, 18, 0.05);
  line-height: 1.4;
}

.build-card-key-timing-label {
  color: var(--wc3-gold);
  font-weight: bold;
}

.build-card-timer {
  margin-top: auto;
  padding-top: 0.75rem;
  border-top: 1px solid rgba(252, 211, 18, 0.12);
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.build-card-elapsed {
  font-size: 1.4rem;
  color: var(--wc3-gold);
  text-shadow: 0 0 8px rgba(252, 211, 18, 0.5);
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.05em;
  min-width: 4ch;
}

.build-card-controls {
  display: flex;
  gap: 0.25rem;
  flex-wrap: wrap;
}

/* ── Right column: step table ── */
.build-card-steps {
  padding: 0;
  overflow-x: auto;
  overflow-y: auto;
  max-height: 420px;
}

.build-steps-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  font-size: 0.8rem;
}

.build-steps-table thead tr {
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
}

.build-steps-table th {
  padding: 0.35rem 0.6rem;
  text-align: left;
  color: var(--wc3-gold);
  font-size: 0.68rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: normal;
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
  position: sticky;
  top: 0;
  background: rgba(10, 8, 4, 0.95);
  z-index: 1;
}

.build-steps-table td {
  padding: 0.35rem 0.6rem;
  color: #dbe4ff;
  vertical-align: middle;
}

/* ── Step states ── */
.build-step-row {
  transition: opacity 0.15s ease;
  /* Reserve border space on every row so the active border doesn't shift layout */
  border: 6px solid transparent;
}

.build-step-row--past {
  opacity: 0.4;
}

.build-step-row--active {
  opacity: 1;
  background: rgba(252, 211, 18, 0.06);
}

.build-step-row--active td {
  color: var(--wc3-gold);
  text-shadow: 0 0 6px rgba(252, 211, 18, 0.35);
}

.build-step-order {
  width: 1.8rem;
  color: rgba(252, 211, 18, 0.5);
  font-size: 0.7rem;
  text-align: center;
}

.build-step-time {
  width: 3.5rem;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}

.build-step-instruction {
  /* takes remaining space */
}

.build-step-food {
  width: 4rem;
  white-space: nowrap;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

@media (max-width: 700px) {
  .build-card {
    grid-template-columns: 1fr;
  }

  .build-card-info {
    border-right: none;
    border-bottom: 1px solid rgba(252, 211, 18, 0.2);
  }
}
